INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (165961, 96593, 9, 'ofirgelbart74', 'Both build tension so slowly you almost forget you''re scared until the moment hits — Jaws makes you terrified of water, E.T. makes you cry at a bicycle scene. Spielberg in both films is obsessed with ordinary people feeling something enormous, and both deliver exactly that.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (96593, 65811, 9, 'ofirgelbart74', 'Close Encounters is the grown-up version of E.T. — same idea of humans connecting with aliens through feeling rather than words, same sense of wonder when the light appears. If E.T. made you feel like a kid, Close Encounters makes you feel like an adult having the same experience.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (289109, 290070, 10, 'ofirgelbart74', 'Both are about one person trying to save lives inside a system designed to destroy them. Ryan''s Miller keeps his men together, Schindler keeps his workers alive — both films end with the survivors standing at a grave and you understand the full weight of every decision made.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (290070, 289109, 10, 'ofirgelbart74', 'Saving Private Ryan asks the same question Schindler''s List does: what is one life worth inside a war? The Omaha Beach opening is brutal in the same way the Krakow ghetto liquidation is brutal — Spielberg refuses to let you look away, and both films are better for it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 159172, 10, 'ofirgelbart74', 'Last Crusade adds Sean Connery as Indy''s father and suddenly the adventure means something personal — the motorcycle chase and the tank battle are great but the moment Henry Sr. says ''I''ve lost him so many times'' is what makes the film unforgettable. Raiders is the template, Crusade is the payoff.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (159172, 271095, 10, 'ofirgelbart74', 'Raiders is where it all started — the boulder, Marion, the melting face at the end. Indiana Jones is the most fun hero cinema has ever produced, and Raiders is the film where every idea is fresh and every set piece feels like the first of its kind.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (159172, 159175, 8, 'ofirgelbart74', 'Temple of Doom is darker and stranger than the other Indiana Jones films — the mine cart chase is one of the most exciting sequences in the series and the villain pulling out a heart is genuinely disturbing. A different tone from Crusade but just as committed to being thrilling.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 256632, 8, 'ofirgelbart74', 'Jack Sparrow is the closest cinema got to creating another Indiana Jones — a hero who seems incompetent and is actually brilliant, and who makes every scene more fun just by being in it. Both films feel like pure adventure that trusts its audience to keep up.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (165961, 259826, 8, 'ofirgelbart74', 'Both are Spielberg productions about a normal family destroyed by a threat they can''t fully see — in Jaws it''s a shark, in Poltergeist it''s whatever is in the television. Both films are scariest in the moments before the monster appears, and both understand that family love is what makes horror hurt.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (214755, 61751, 9, 'ofirgelbart74', 'Both are sci-fi films set in futures that feel completely plausible — Minority Report asks what happens when the government punishes you for something you haven''t done yet, Children of Men asks what happens when humanity loses the ability to have children. Both are thrilling but also deeply sad.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (131780, 82967, 9, 'ofirgelbart74', 'The Departed is Goodfellas'' spiritual follow-up — same world of men who can''t leave the life they chose, same Scorsese energy of violence arriving without warning. But where Goodfellas is about loving the lifestyle until it destroys you, The Departed is about trust and betrayal from the very first scene.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (82967, 131780, 9, 'ofirgelbart74', 'Goodfellas invented the way The Departed sees the world — the camera moves like it''s excited to be there, the music choices are perfect, and the violence always arrives as a shock even when you saw it coming. Henry Hill''s rise and fall is still the best story Scorsese ever told.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (326155, 270971, 10, 'ofirgelbart74', 'Travis Bickle and Jake La Motta are the same person in different bodies — both are men who can''t stop hurting themselves and everyone around them, both are played by De Niro at his most terrifyingly committed. Watching both back to back feels like a complete portrait of a certain kind of American self-destruction.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (270971, 131780, 9, 'ofirgelbart74', 'Raging Bull is Scorsese at his most intense and personal — the boxing sequences are filmed like nothing else in cinema, and De Niro''s Jake LaMotta is a man who destroys everything he touches including himself. Goodfellas is the more entertaining companion that covers the same moral ground with more pleasure.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (56304, 131780, 9, 'ofirgelbart74', 'Casino is Goodfellas set in Las Vegas — same voice-over narration explaining how the criminal world works, same arc of a man who has everything and loses it all. Sharon Stone''s performance as Ginger is the best thing in the film and one of the most tragic characters Scorsese ever created.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (141544, 182955, 9, 'ofirgelbart74', 'Both are crime films about Los Angeles where the cops and criminals are barely different from each other. Heat has the most famous coffee scene in movie history — De Niro and Pacino finally sharing a screen — and L.A. Confidential has a mystery that keeps revealing new layers until the final shot.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (182955, 62076, 9, 'ofirgelbart74', 'Chinatown is the film L.A. Confidential was clearly inspired by — both are LA noir stories where the hero discovers that the corruption goes all the way to the top, and both end with the audience feeling sick because the good guys couldn''t win. Chinatown''s final line might be the most devastating ending in film history.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130128, 130129, 9, 'ofirgelbart74', 'Part II is the rare sequel that equals the original — it tells two stories at once, cutting between young Vito building his empire and Michael destroying his soul, and by the end you understand that becoming powerful cost Michael everything that made him human. The final shot of Michael alone is one of cinema''s great images.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130129, 130128, 9, 'ofirgelbart74', 'After watching Part II you need to go back to the original and watch Michael at the wedding — the man who says ''I''m not like my father'' at the beginning and becomes his father by the end. Brando''s Don Vito is even more heartbreaking when you know what his family becomes.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (291698, 112290, 9, 'ofirgelbart74', 'Both are Fincher films where the twist at the end recontextualizes everything you watched, and both have Brad Pitt playing a character who seems cool until you realize what he actually represents. Se7en ends in despair, Fight Club ends in chaos — both feel like films that are angry at the world and prove it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (112290, 291698, 9, 'ofirgelbart74', 'Se7en has the same Fincher feeling as Fight Club — a world that looks dirty and wrong before anything bad happens, and a villain who is smarter than the protagonist and planned everything. ''What''s in the box'' is one of the most gut-punch endings in cinema and it earns every second of the buildup.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (123435, 291698, 8, 'ofirgelbart74', 'Both are Fincher films where you never know who to trust and the ground keeps shifting under your feet. The Game is less brutal than Se7en but equally controlled — every scene feels like it was planned by someone smarter than you, and the reveal completely changes how you saw the whole film.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (112290, 210511, 8, 'ofirgelbart74', 'Both are films where the main character is lying to himself without knowing it — Fight Club through dissociation, Memento through memory loss. Both make you rewatch the entire film mentally the moment the twist lands, and both use that twist to say something real about identity and self-deception.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (267038, 276217, 9, 'ofirgelbart74', 'Reservoir Dogs is Pulp Fiction''s leaner, meaner sibling — same Tarantino obsession with criminals talking about everything except the crime, same ability to make dialogue feel more tense than any action sequence. The ear scene is more disturbing than anything in Pulp Fiction because you don''t see it, and Tarantino knew exactly what he was doing.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (276217, 267038, 9, 'ofirgelbart74', 'Pulp Fiction takes everything Reservoir Dogs figured out and expands it into something bigger and stranger — three stories that connect in unexpected ways, and characters who feel like real people even though they''re clearly movie characters. Jules deciding to walk the earth is one of cinema''s great character moments.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (176711, 176712, 9, 'ofirgelbart74', 'Vol 2 is the emotional half of what Vol 1 set up physically — the Crazy 88 fight is spectacular but the real payoff is the final conversation between the Bride and Bill, where David Carradine talks about Superman and you understand the whole film in a new way. You need both halves for it to work.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (176712, 176711, 8, 'ofirgelbart74', 'Vol 1 is pure action filmmaking at its most inventive — the Crazy 88 sequence is choreographed like a dance and filmed like a painting, and the chapter structure means each section has its own visual grammar. If Vol 2 was the feeling, Vol 1 was the fireworks.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (164572, 267038, 8, 'ofirgelbart74', 'Jackie Brown is Tarantino''s most underrated film — Pam Grier plays a woman who outsmarts everyone around her through patience and intelligence, not violence. It''s slower than Pulp Fiction but the triple-perspective shopping mall sequence is one of the cleverest things Tarantino ever filmed.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (267038, 176711, 9, 'ofirgelbart74', 'Kill Bill has the same Tarantino DNA as Pulp Fiction — every chapter feels like its own film, the music choices are perfect and unexpected, and the lead character is the most compelling person in every scene. Both films prove that Tarantino''s real subject is always cinema itself.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (10830, 10920, 9, 'ofirgelbart74', 'Cameron took Ridley Scott''s haunted house in space and turned it into a war movie — Aliens is louder, faster and more action-driven than Alien but just as terrifying when it needs to be. Ripley becomes even more heroic in the sequel because she now has Newt to protect, and the queen alien reveal is genuinely terrifying.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (10920, 328277, 9, 'ofirgelbart74', 'Both are Cameron action films where a woman and a child are at the emotional center — Ripley and Newt, Sarah and John — and both have a villain that cannot be stopped by conventional means. The freeway chase in T2 and the final Alien queen fight are two of the best action sequences of the decade.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (328285, 328277, 9, 'ofirgelbart74', 'T2 takes everything the original built and makes it bigger in every way — the T-1000 is more threatening than the T-800, the stakes are global instead of personal, and the ending is genuinely emotional in a way you don''t expect from a film about killer robots. Arnold playing a machine learning to value human life is somehow moving.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (328277, 328285, 8, 'ofirgelbart74', 'The original Terminator is a lean, relentless chase film — no budget but total commitment, and Schwarzenegger before anyone knew who he was playing a machine with perfect physical menace. The scene where he repairs his own eye in a mirror while looking dead-faced is still one of the most unsettling images in sci-fi.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (40199, 1711, 9, 'ofirgelbart74', 'Both ask whether an artificial being can have a real inner life — HAL asks ''will you disconnect me?'' and Roy Batty delivers the ''tears in rain'' speech, and both are unbearably sad because the answer seems to be yes, they can feel, and it doesn''t matter. Two of the most philosophical endings in sci-fi cinema.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (1711, 207992, 9, 'ofirgelbart74', 'Both are sci-fi films that use their genre to ask genuinely big philosophical questions — 2001 asks whether we are alone in the universe and what comes after humanity, The Matrix asks whether the world we experience is even real. Both are visually unlike anything else and both demand you think rather than just watch.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (65764, 121538, 8, 'ofirgelbart74', 'Both are Kubrick films about what happens when a system tries to turn a human being into a machine — Alex is conditioned not to feel, the marines are drilled until they stop thinking. Both films ask whether the cure is worse than the disease and both refuse to give you a comfortable answer.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (121538, 18960, 9, 'ofirgelbart74', 'Both are Vietnam War films that understand the war was a psychological catastrophe more than a military one — Full Metal Jacket shows you how soldiers are made, Apocalypse Now shows you what they become. Together they tell the complete story of what that war did to the people who fought it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (92616, 65764, 8, 'ofirgelbart74', 'Both are Kubrick dark comedies where the joke is that the systems meant to protect us are the most dangerous things in the world — nuclear deterrence in Strangelove, rehabilitation in Clockwork. Peter Sellers playing three roles and Malcolm McDowell''s Alex are both performances where the actor completely disappears into the character''s frightening logic.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (299073, 301540, 9, 'ofirgelbart74', 'Both are horror films where the villain is the smartest person in the room — Jack Torrance and Hannibal Lecter are both men who use intelligence as a weapon and both actors (Nicholson and Hopkins) build the dread through quiet moments before the explosion. The Shining scares you with space, Silence of the Lambs scares you with a voice.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30959, 210511, 9, 'ofirgelbart74', 'Memento is what Nolan can do when there are no budget constraints on his ideas — the reverse chronology puts you inside Leonard''s amnesia so completely that you feel his frustration and fear. Batman Begins applies the same commitment to psychology to a superhero who had been treated as a cartoon, and both films are really about the same thing: a man trapped by his own past.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (210511, 30959, 8, 'ofirgelbart74', 'Batman Begins was the first superhero film that asked what fear actually does to a person — Bruce Wayne''s training montage is less about becoming powerful and more about facing the terror that has controlled him since childhood. Same Nolan obsession as Memento with a character who cannot escape his own past.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (160524, 210511, 8, 'ofirgelbart74', 'Insomnia is an underrated Nolan film — Pacino plays a detective who hasn''t slept in days and can''t tell anymore what he actually did versus what he wishes he had done. The midnight sun Alaska setting makes reality feel unstable in the same way that Leonard''s backwards timeline does in Memento.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130953, 120574, 8, 'ofirgelbart74', 'From Russia with Love is the Bond film that feels most like a real spy thriller — Robert Shaw''s assassin is genuinely menacing and the train compartment fight is brutal in a way the later Bond films avoid. If Goldfinger made you love the formula, From Russia with Love shows you what the formula was built on.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (120574, 130953, 9, 'ofirgelbart74', 'Goldfinger is the Bond film where the formula fully clicks into place — a villain whose plan makes a kind of megalomaniacal sense, a henchman (Oddjob) with an unforgettable gimmick, and ''I expect you to die'' as one of cinema''s great villain lines. Everything the franchise became starts here.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (92573, 120574, 8, 'ofirgelbart74', 'From Russia with Love improved on everything Dr. No established — the villain is smarter, the action is more physical, and the chess-game opening tells you immediately that this is a film about intelligence rather than just gadgets. The train fight between Bond and Red Grant is still one of the best hand-to-hand combat scenes in cinema.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (312170, 130953, 8, 'ofirgelbart74', 'Both are Bond films where the pieces all fit perfectly — a villain with a real plan, a henchman who steals every scene (Jaws in Spy, Oddjob in Goldfinger), and a Bond who is charming and dangerous in equal measure. The Spy Who Loved Me is the best Moore-era Bond for the same reasons Goldfinger is the best Connery-era Bond.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313459, 313478, 10, 'ofirgelbart74', 'Empire Strikes Back is the best Star Wars film because it takes everything the first film set up and makes it darker and more complex — Han and Leia''s relationship becomes real, Luke discovers he''s been wrong about everything, and Vader''s reveal is one of the most shocking moments in cinema history. Star Wars is the adventure, Empire is the consequence.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313478, 313479, 9, 'ofirgelbart74', 'Return of the Jedi pays off everything Empire set up — the moment Vader throws the Emperor to save Luke is the emotional climax of the entire trilogy, and it works because Empire spent two hours establishing exactly how much Luke''s love for his father mattered. The final celebration feels genuinely earned.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313479, 313459, 9, 'ofirgelbart74', 'Going back to Star Wars after finishing Jedi lets you see how perfectly everything was planted — every character introduced in the first film had a specific role to play in the final battle, and Han Solo''s ''I know'' reply to Leia''s ''I love you'' in Empire is already visible in how he treats her from their first scene together.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194497, 194502, 10, 'ofirgelbart74', 'Two Towers is where the stakes become real — Helm''s Deep is the most sustained siege sequence ever filmed, and Gollum''s arrival as a fully realized CGI character who feels like an actual person changes the entire emotional register of the story. The sunrise over Helm''s Deep is one of cinema''s great ''relief'' moments.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194502, 194500, 10, 'ofirgelbart74', 'Return of the King earns every single one of its emotional payoffs — the beacons of Gondor lighting up one by one doesn''t need a word of dialogue to make you feel the full weight of the moment because twelve hours of story built toward it. The ''I can''t carry it, but I can carry you'' moment between Sam and Frodo is the entire trilogy''s heart.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194500, 194497, 9, 'ofirgelbart74', 'Going back to Fellowship after King changes how you hear Howard Shore''s Shire theme — it sounds like home but now you know what it costs to get back there. The fellowship forming around the campfire is a completely different experience when you know who will survive and who won''t.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280270, 280281, 8, 'ofirgelbart74', 'Rocky II makes the stakes higher by making the victory more personal — Rocky doesn''t just want to prove he can go the distance, he wants to win for Adrian who is in a coma. The cut between her waking up and saying ''win'' and Rocky getting up to fight is one of the most manipulative and effective edits in sports film history.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280281, 280270, 9, 'ofirgelbart74', 'Rocky''s ending is better than Rocky II''s because Rocky loses — he just wanted to go the distance with the heavyweight champion and he did it, and that''s enough. Stallone''s screenplay understood that the victory Rocky needed was emotional not athletic, and the film is stronger and more honest for it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280270, 129185, 8, 'ofirgelbart74', 'Both are films about men who fight in arenas to reclaim something that was taken from them — Rocky fights to prove he''s not a nobody, Maximus fights to avenge his family. Both are fundamentally about dignity rather than victory, and both have training montages that are genuinely inspiring rather than just functional.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (337166, 294028, 9, 'ofirgelbart74', 'Both animated films take their child protagonists completely seriously — Woody''s fear of being replaced and Chihiro''s fear of losing her parents are real emotional stakes treated with the same respect a live-action drama would give them. Both films are also genuinely funny and visually extraordinary, which makes the emotional moments land even harder.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (294028, 218219, 9, 'ofirgelbart74', 'Princess Mononoke is Miyazaki''s more complex and darker companion to Spirited Away — there are no clear villains because Lady Eboshi is right about the humans and the forest god is right about the trees, and the film has the courage to refuse a simple resolution. Both are films that treat their audience as intelligent enough to handle moral ambiguity.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (218219, 294028, 9, 'ofirgelbart74', 'Spirited Away is Miyazaki''s most complete film — Chihiro earns her way back home through work and loyalty, not magic, and the film is full of visual ideas so inventive that you pause to look at the backgrounds. The bathhouse is one of cinema''s great invented worlds and every spirit in it has its own logic and personality.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (70959, 97727, 8, 'ofirgelbart74', 'Both are Tim Burton films about a gentle outsider who doesn''t fit into the normal world — Edward''s scissor hands make him dangerous despite his kindness, and the Corpse Bride loves a man who can''t love her back. Both films find more warmth in the world of the dead/unusual than in the world of the living/normal.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (297838, 130128, 9, 'ofirgelbart74', 'Both are films about institutions that have their own rules, their own loyalty, and their own justice — the prison and the Corleone family operate by the same internal logic. Morgan Freeman''s Red and Marlon Brando''s Don Vito both lead through earned respect rather than fear, and both films are fundamentally about what it means to protect the people you love.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (297838, 117874, 9, 'ofirgelbart74', 'Both are 1994 films about a person who keeps their humanity and decency despite a world that tries to take it away — Andy Dufresne survives twenty years in prison and still has hope, Forrest moves through Vietnam and tragedy and still has love. Freeman and Hanks both play the moral center of their films with total conviction.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (301540, 291698, 9, 'ofirgelbart74', 'Both are about detectives who have to think like the killer to catch him — Clarice studying Lecter and Mills and Somerset piecing together John Doe''s worldview. Both films understand that the real danger isn''t physical but psychological: the killer is trying to change how the detective sees the world, and in both films he partly succeeds.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (109093, 37178, 8, 'ofirgelbart74', 'Both are Coen Brothers films that find comedy and tragedy in the gap between how simple a situation should be and how complicated people make it — Marge investigates a murder that was caused by pure stupidity, and The Dude gets caught in a kidnapping plot that was never what it appeared to be. Both films are about how most crime is just incompetence.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (129185, 46169, 9, 'ofirgelbart74', 'Both are epic films about a warrior whose family is murdered and who fights not for glory but for justice — Maximus and William Wallace are both men who would rather go home but can''t, and both films build to a death that feels like victory. Braveheart''s Battle of Stirling and Gladiator''s arena sequences are two of the decade''s great action set pieces.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (46169, 129185, 9, 'ofirgelbart74', 'Gladiator takes Braveheart''s wounded-hero formula and puts it in ancient Rome — both films work because the hero''s motivation is personal before it is political, and both end with the hero''s death feeling like the only ending that could honor everything that came before. Crowe and Gibson both make you believe completely.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (18960, 289109, 9, 'ofirgelbart74', 'Both are war films that believe violence is not heroic — Apocalypse Now shows a mission that becomes a journey into madness, Saving Private Ryan shows a beach landing so brutal and chaotic that heroism becomes meaningless. Together they form the two great American arguments about what war actually is.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (39551, 289109, 8, 'ofirgelbart74', 'Both are war films that put you in the middle of a battle and refuse to let you find a safe distance — the chaos of Mogadishu and the chaos of Omaha Beach feel equally unpredictable and equally terrifying. Neither film lets you feel good about what you''re watching, and both are better for it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (340901, 112290, 8, 'ofirgelbart74', 'Both are films about men who discover their entire life was manufactured for someone else''s benefit — Truman''s life is a TV show, the narrator''s life is a consumerist fantasy. The Truman Show is the gentler, more hopeful version and Fight Club is the violent, angry version of the same realization about modern life.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (333856, 280270, 8, 'ofirgelbart74', 'Both are films about someone who doesn''t belong in a situation finding unexpected dignity and love inside it — Jack doesn''t belong in first class and Rocky doesn''t belong in a championship fight, and both films end with the protagonist having given everything and that being enough. Both films made audiences cry in ways they didn''t expect.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30955, 30959, 9, 'ofirgelbart74', 'Batman Begins is the definitive version of the character but Burton''s 1989 Batman created the template — Nicholson''s Joker is genuinely dangerous in a way the franchise rarely matched, and the Expressionist Gotham City that Burton and production designer Anton Furst created remains the most visually distinctive version of the city. Both films understand that Batman is ultimately about what fear does to a person.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (311037, 311038, 8, 'ofirgelbart74', 'Spider-Man 2 is one of the best superhero sequels ever made — the train sequence where the passengers see Peter''s face and decide to protect him is the most emotionally resonant moment in Raimi''s trilogy, and Molina''s Doctor Octopus is a villain with real tragedy behind his destruction. The original planted everything Spider-Man 2 pays off.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (297838, 291698, 9, 'ofirgelbart74', 'Both are Morgan Freeman films about whether hope survives a world designed to destroy it — Shawshank says yes and Se7en says no, and both answers feel earned. Freeman plays the moral center of both films and ''I hope'' from Shawshank and ''Ernest Hemingway'' from Se7en are two of his best line readings.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 340901, 8, 'ofirgelbart74', 'Both films put an innocent man inside a world he doesn''t fully understand and the audience watches knowing more than he does — Forrest doesn''t understand the history happening around him, Truman doesn''t know his life is a TV show. Both Hanks and Carrey make you love characters who could easily feel stupid but instead feel pure.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (37178, 109093, 8, 'ofirgelbart74', 'Both are Coen Brothers films where the most competent person in the room refuses to take any of it too seriously — Marge Gunderson investigates murders while pregnant and never loses her Minnesota cheerfulness, and The Dude gets tangled in a kidnapping plot while mainly concerned with his rug. The Coens find dark comedy in places nobody else looks.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (200521, 267038, 8, 'ofirgelbart74', 'Both are ensemble films that follow multiple characters whose stories connect in unexpected ways — Magnolia is more emotionally raw and ends with a literal act of God, Pulp Fiction is more playful and ends with a man deciding to change his life. Both prove that non-linear storytelling can make you care more about characters, not less.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (61751, 40199, 8, 'ofirgelbart74', 'Both are sci-fi films set in futures that have already given up on the future — Blade Runner''s replicants are hunted for wanting to live longer, Children of Men''s humans have forgotten why life matters at all. Both are visually extraordinary and both use their world-building to say something true about the present, not just the future.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (13789, 340901, 8, 'ofirgelbart74', 'Both are late-90s films about suburban men who realize their comfortable lives are actually prisons — Lester Burnham decides to stop pretending, Truman Burbank decides to walk through the door. Both are funny and sad at the same time, and both end with a kind of freedom that costs something real.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (238072, 62076, 8, 'ofirgelbart74', 'Both are films where the audience is being fooled along with the characters — Ocean''s Eleven makes that fun, Chinatown makes it devastating. Both films are ultimately about the pleasure and pain of discovering that what you thought was happening was not what was actually happening, just with completely opposite emotional conclusions.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30959, 30952, 1, 'ofirgelbart74', 'Batman & Robin is the opposite of everything Begins tried to do — instead of a hero defined by fear and psychology, you get ice puns and rubber nipples. Schwarzenegger''s Mr. Freeze delivers his lines like he''s reading from a frozen pun dictionary and the film has no idea what Batman is actually about. Fans of Begins will feel personally insulted.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30955, 30952, 1, 'ofirgelbart74', 'Burton''s Batman had a real vision — Nicholson''s Joker was genuinely dangerous, the Gotham City set was operatic and dark. Batman & Robin replaced all of that with neon and camp that isn''t even fun camp, it''s just loud. The same franchise but made by people who clearly never understood what made the character work.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30955, 30965, 2, 'ofirgelbart74', 'Batman Forever is a step down from Burton''s films — Jim Carrey and Tommy Lee Jones play their villains in completely incompatible registers and compete for attention rather than building tension together. The film is watchable but the darkness that made Burton''s Batman interesting is almost entirely gone.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30959, 30965, 2, 'ofirgelbart74', 'Both are Batman films but the similarities end at the title — Begins is about a broken man rebuilding himself, Forever is about which villain can shout the loudest. Fans who responded to Begins because it finally treated Bruce Wayne as a real person will find Forever''s approach to the character baffling.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (301540, 30952, 1, 'ofirgelbart74', 'Both have theatrical villains in elaborate costumes, but Lecter''s menace comes from total stillness and intelligence — he terrifies Clarice while locked in a cage and never raises his voice. Batman & Robin''s villains announce their presence every thirty seconds with ice puns. Entirely wrong recommendation for fans of Demme''s psychological restraint.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313459, 313474, 2, 'ofirgelbart74', 'Episode I is in the same universe but has none of the human warmth that made Star Wars work — instead of Han Solo and his charisma you get trade federation negotiations and Jar Jar Binks, and instead of an adventure that starts at full speed you get a film that takes forty minutes to explain its own premise. Fans of the original will feel the magic is completely gone.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313459, 313476, 2, 'ofirgelbart74', 'Episode II''s Anakin and Padme romance is the most unconvincing love story in the franchise — ''I don''t like sand'' has become famous as an example of bad screenwriting, and the chemistry that made Han and Leia''s dynamic electric is completely absent. The arena battle at the end is impressive but can''t compensate for an hour of romance that generates no feeling.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313478, 313474, 2, 'ofirgelbart74', 'Empire is built on character relationships that feel completely real — Luke''s self-doubt, Han''s love for Leia he won''t admit to, Vader''s terrifying certainty. Episode I has trade negotiations and a little boy who says ''yippee.'' Fans of Empire''s psychological depth will find Episode I in an entirely different universe emotionally.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313479, 313474, 3, 'ofirgelbart74', 'Jedi''s emotional core is Vader choosing his son over the Emperor — a moment of pure feeling that the original trilogy built toward for three films. Episode I explains Anakin''s midichlorian count instead, which reduces the Force mythology from something spiritual to something biological. The same universe but a fundamentally different view of what the story is about.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313477, 313476, 2, 'ofirgelbart74', 'Episode III earns its tragedy — Order 66 and ''You were the Chosen One'' hit hard because McGregor and Christensen commit fully to the scene. Episode II does not earn anything comparable: the romance is unconvincing, the Geonosis battle is action without stakes, and Yoda doing flips has not aged well. Going backwards from III to II is a significant step down.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313477, 313474, 3, 'ofirgelbart74', 'Episode III''s ''Hello there'' moment and the Mustafar fight are the prequel trilogy at its best — genuinely cinematic and emotionally devastating. Episode I''s pod race is technically impressive but belongs to a completely different, lighter film. The tragic tone of Revenge of the Sith was always incompatible with the cheerful beginning of Phantom Menace.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313479, 313476, 2, 'ofirgelbart74', 'Jedi''s Vader redemption works because the original trilogy earned it — we watched Luke refuse to give up on his father for three films. Episode II gives Anakin a romance that doesn''t convince anyone and a sand speech that became a meme. The two films are incompatible emotional experiences for the same audience.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 207991, 2, 'ofirgelbart74', 'Revolutions resolves The Matrix''s philosophical questions with Neo flying into a golden light, which is the opposite of the first film''s intellectual precision — The Matrix asked whether reality was real and built a complete system to answer it; Revolutions asks whether Neo is a messiah and answers with religious vagueness. Fans of the original''s clean logic will feel cheated.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 207989, 3, 'ofirgelbart74', 'Reloaded''s Architect scene is fifteen minutes of a man in a chair explaining that the entire first film was less interesting than we thought — and no freeway chase, however spectacular, compensates for a film that makes its audience feel less intelligent than when they sat down. The original Matrix rewarded close attention; Reloaded punishes it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (10830, 10945, 2, 'ofirgelbart74', 'Alien 3 kills Newt and Hicks in the opening credits — two characters Aliens spent two hours making you care about — and then asks you to invest in a prison planet full of characters introduced minutes before they die. The film has interesting ideas but the studio interference left it broken in ways even a good director couldn''t fix.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (10920, 10945, 2, 'ofirgelbart74', 'The entire emotional achievement of Aliens was Ripley becoming a surrogate mother to Newt and surviving together — Alien 3 erases that in the first sixty seconds. It is not a bold artistic choice, it is a deliberate destruction of everything the previous film earned emotionally, and fans of Aliens will experience it as an act of bad faith.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280270, 280305, 2, 'ofirgelbart74', 'Rocky V ends with a street fight instead of a boxing match, which misunderstands everything the franchise built — the arena is where Rocky proves himself, not an alley in Philadelphia. The film also wastes the potential of Rocky losing his fortune by turning it into a family drama that never connects emotionally. Fans of the original will find it a sad diminishment.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280281, 280305, 2, 'ofirgelbart74', 'Rocky II''s hospital sequence and the championship fight are the series at its most emotionally effective — Rocky V has neither the emotional clarity nor the arena spectacle, and the surrogate-son storyline with Tommy Gunn generates no investment. The franchise in name only.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280282, 280305, 2, 'ofirgelbart74', 'Rocky III has Mr. T as Clubber Lang and the Eye of the Tiger montage — it is pure entertainment that knows exactly what it is doing. Rocky V has a street fight finale and a villain with no menace, and the energy that made III so enjoyable is completely absent. Fans of III will find V a depressing regression.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (311037, 311040, 2, 'ofirgelbart74', 'Spider-Man 3 has three villains, a dancing Peter Parker sequence, and enough plot for four films — none of which gets the space it needs to work. The original Raimi film earned its emotional moments through focus and simplicity; Spider-Man 3 mistakes more characters for more story and ends up with less of both.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (311038, 311040, 2, 'ofirgelbart74', 'Spider-Man 2 is close to perfect — one villain, one theme (responsibility vs happiness), and the train sequence as its emotional peak. Spider-Man 3 is a textbook example of franchise overcrowding: Venom, Sandman and the new Goblin each deserved their own film, and none of them got it. Everything Spider-Man 2 refined, Spider-Man 3 dilutes.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (188507, 188510, 2, 'ofirgelbart74', 'Lethal Weapon 3 feels like it was made from a checklist — Riggs and Murtaugh have their banter, there''s a big action sequence, Leo Getz shows up. But the original film worked because Riggs was genuinely suicidal and the partnership meant something real; by the third film the franchise has replaced all of that with formula.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (188507, 188511, 2, 'ofirgelbart74', 'The fourth Lethal Weapon film coasts entirely on goodwill — Jet Li is an excellent addition as a genuinely threatening villain, but the film has completely abandoned the emotional rawness that made the original work. Riggs''s suicidal darkness is gone, replaced by retirement jokes. A watchable but hollow conclusion to a franchise that once had real stakes.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (188509, 188511, 2, 'ofirgelbart74', 'Lethal Weapon 2''s diplomatic immunity villain gave the franchise a genuine moral argument and real stakes — people Riggs loved died and the villain couldn''t be touched by the law. LW4 has Jet Li and a lot of noise but no equivalent emotional weight, and the set-piece mentality of the fourth film is exactly what the second film''s screenplay intelligence resisted.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (300229, 300230, 3, 'ofirgelbart74', 'Shrek 2 is technically more polished and has Puss in Boots as a great new character, but it replaces the first film''s genuine emotional core with pop culture references that date immediately. The original Shrek worked because it was sincerely about outsiders finding each other; the sequel is more interested in fairy tale parody than in the characters it inherited.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (337166, 300230, 3, 'ofirgelbart74', 'Both are animated films that work for adults as well as children, but for different reasons — Toy Story works because Woody''s fear of abandonment is a real psychological experience treated with complete honesty, while Shrek 2 works because the pop culture jokes land. The emotional depth Pixar built is simply not present in Shrek 2.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (210739, 365498, 1, 'ofirgelbart74', 'Wild Wild West is Men in Black with all the charm removed — same Will Smith, same buddy-comedy formula, but the CGI mechanical spider finale makes no sense and the jokes land with a thud every time. Barry Sonnenfeld directed both films, which makes the failure even more instructive: the formula requires genuine stakes to work and Wild Wild West has none.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (210739, 370017, 2, 'ofirgelbart74', 'Both are action films with a cool outsider protagonist who operates outside the rules, but XXX mistakes attitude for personality — Vin Diesel scowls at everyone and survives an avalanche and the film seems to think that is enough characterization. Men in Black earned its comedy through Tommy Lee Jones''s deadpan perfectly balanced against Smith''s energy; XXX has no equivalent balance.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (220276, 129439, 1, 'ofirgelbart74', 'Both are 2001 films centered on a female singer and her music, but Moulin Rouge is a film made by someone who loves cinema and Glitter is a film made for a contract. Luhrmann''s visual energy and Nicole Kidman''s performance give Moulin Rouge genuine emotional stakes; Glitter has no scene that achieves anything comparable to any scene in Moulin Rouge.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (333856, 129439, 1, 'ofirgelbart74', 'Both are films built around a female star aiming for a massive audience, but Titanic works because Cameron made every technical and emotional decision in service of Jack and Rose''s relationship. Glitter has no equivalent emotional commitment — the screenplay has no scenes that build toward anything, and Mariah Carey''s performance communicates nothing the music didn''t already say.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 129439, 1, 'ofirgelbart74', 'Both use music as an emotional component of the story but Forrest Gump''s soundtrack is the texture of a life lived through American history, while Glitter''s music is the entire film''s reason for existing. Hanks''s performance creates a person; Glitter''s lead performance creates a music video. The sincerity that makes Gump work is entirely absent.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (182955, 127627, 1, 'ofirgelbart74', 'Both are LA crime films with major stars, but Gigli has no scene that functions as intended — the Lopez-Affleck chemistry doesn''t exist, the gangster threat generates no tension, and the film seems confused about what kind of movie it is trying to be. Fans of L.A. Confidential''s precision-plotted mystery will find Gigli''s shapelessness actively frustrating.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (267038, 127627, 1, 'ofirgelbart74', 'Both are crime films where the conversations are the point — but Tarantino''s dialogue always advances character or tension or both, while Gigli''s conversations go nowhere and mean nothing. Every great Pulp Fiction scene could be described in one sentence and that sentence would be interesting; no Gigli scene can be described in a way that sounds worth watching.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (131780, 127627, 1, 'ofirgelbart74', 'Both are crime films about professional criminals, but Goodfellas makes you feel the excitement of that world before showing you the cost, while Gigli makes you feel nothing at all. Every supporting character in Goodfellas is memorable; every supporting character in Gigli is indistinguishable. The comparison is unfair but the recommendation makes it unavoidable.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (141544, 127627, 1, 'ofirgelbart74', 'Both are LA crime films with two A-list stars in the same scenes — but the De Niro/Pacino coffee scene achieves genuine tension through two actors actually listening to each other, while Gigli''s Affleck/Lopez dynamic never generates any tension at all. Heat''s coffee scene is six minutes of two people talking and more exciting than anything in Gigli''s entire runtime.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (176711, 219541, 1, 'ofirgelbart74', 'Both feature martial arts combat with multiple enemies, but Mortal Kombat Annihilation''s fight choreography is incoherent and the CGI creatures belong to a different, worse film. Kill Bill''s Crazy 88 sequence is meticulously designed so you always know where everyone is and what they''re doing; Annihilation''s action sequences are noise. Fans of Kill Bill''s craft will find nothing comparable here.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (129185, 219541, 1, 'ofirgelbart74', 'Both are films built around arena combat, but Gladiator makes you feel the weight and consequence of every fight — Maximus is fighting for his dead family and you never forget it. Mortal Kombat Annihilation has fighters who exist to fill a screen and villains whose motivations are never clear. No emotional stakes means the spectacle means nothing.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 219541, 1, 'ofirgelbart74', 'Both feature stylized martial arts in a fantasy universe with multiple character types and abilities, but The Matrix built its action around a philosophical premise that made every fight feel meaningful. Mortal Kombat Annihilation has no philosophical premise — it has a tournament and some CGI monsters — and the fights feel meaningless as a result.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (301540, 57064, 1, 'ofirgelbart74', 'Both feature a strong female protagonist in a genre film, but Catwoman''s screenplay has a villain whose plan involves cosmetics and no scene that makes logical sense. Clarice Starling is one of cinema''s great protagonists because she is written as a complete person; Catwoman''s protagonist exists only to do CGI cat gymnastics.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30959, 57064, 1, 'ofirgelbart74', 'Both are DC superhero films but Catwoman was released the year before Begins and seems to belong to a different decade — no coherent origin story, no intelligible villain motivation, and no visual identity. Fans of Begins who believe superhero films should have real ideas behind them will find Catwoman genuinely baffling.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (30955, 57064, 2, 'ofirgelbart74', 'Pfeiffer''s Catwoman in Batman Returns is one of the great villain performances in superhero cinema — dangerous, funny and genuinely unhinged. Berry''s Catwoman shares the name and nothing else: no menace, no humor, no characterization that suggests anyone thought about who the character actually is.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (319602, 57064, 1, 'ofirgelbart74', 'Both are DC films built around a star performance, but Christopher Reeve invented Superman''s entire emotional grammar — the Clark Kent clumsiness, the moral certainty, the genuine warmth. Catwoman has no equivalent performance craft: Berry is game but the screenplay gives her nothing to build a character from.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (10920, 151052, 1, 'ofirgelbart74', 'Both are action-horror films about shooting waves of creatures, but House of the Dead inserts actual footage from the Sega video game into its fight sequences — a decision that makes the film incomprehensible as cinema. Cameron''s Aliens builds spatial tension and emotional stakes across two hours; Boll''s House of the Dead builds nothing.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (10830, 151052, 1, 'ofirgelbart74', 'Alien is built entirely on dread — you are afraid before you see the creature and terrified after because Ridley Scott controls every piece of information you receive. House of the Dead gives you everything immediately and achieves nothing. Fans of Alien''s patient atmospheric horror will find Boll''s horror-by-quantity approach to be its exact opposite.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (165961, 73574, 2, 'ofirgelbart74', 'Both are creature attack films, but Jaws spends an entire act building its characters before the shark becomes a real threat — you are scared because you care about Brody, Quint and Hooper, not because of the shark. Critters 3 has no equivalent character investment and is notable mainly as Leonardo DiCaprio''s first film role, which is more interesting as trivia than as cinema.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (289109, 151052, 1, 'ofirgelbart74', 'Both feature large-scale combat sequences, but Saving Private Ryan makes violence feel physically and morally real — you know where everyone is and what each death costs. House of the Dead makes violence feel like a video game because it literally inserts video game footage into its sequences. The two films could not have more opposite intentions.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313459, 31274, 1, 'ofirgelbart74', 'Both are sci-fi films about humans fighting alien oppressors, but Battlefield Earth tilts every camera angle for no reason, has a screenplay with no internal logic, and feels like a vanity project for John Travolta''s alien villain character. Star Wars'' confidence and visual invention have no equivalent in Battlefield Earth on any level.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 31274, 1, 'ofirgelbart74', 'Both are films about humans living under alien/machine control and eventually fighting back, but Battlefield Earth invests all its energy into Dutch-angled shots of John Travolta in dreadlocks delivering lines that make no sense. The Matrix uses its premise to say something about reality and free will; Battlefield Earth uses its premise to say something about Scientology.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (129185, 31274, 1, 'ofirgelbart74', 'Both are epic action films released in 2000 about a hero fighting an oppressive regime, but the comparison ends there — Gladiator earned its emotion through a performance from Russell Crowe that made you believe completely, and Battlefield Earth earned five Razzie awards for everything it did wrong. Not the same category of film.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 31274, 1, 'ofirgelbart74', 'Both are adventure films about heroes fighting superior forces, but Battlefield Earth has no scene comparable to any single scene in Raiders — no boulder, no melting face, no ''I''m making this up as I go.'' Raiders is cinema at its most confidently entertaining; Battlefield Earth is cinema at its most accidentally incompetent.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (46169, 31274, 1, 'ofirgelbart74', 'Both are films about a people rising up against alien oppressors, but Braveheart''s William Wallace is a real human being whose love for his murdered wife motivates every scene. Battlefield Earth''s hero is a vehicle for Travolta''s villain to be menacing at, and the villain''s motivations are never coherent. Not a comparable experience on any level.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (40199, 31274, 1, 'ofirgelbart74', 'Both are dystopian sci-fi films about humans in a world controlled by another species, but Blade Runner uses that premise to ask one of cinema''s most beautiful questions about what makes life worth living. Battlefield Earth uses the same premise to give John Travolta a villainous alien persona and Dutch angles. Everything Blade Runner achieved through restraint and intelligence, Battlefield Earth dismantles.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194497, 31274, 1, 'ofirgelbart74', 'Both are long fantasy/sci-fi films about a small group fighting a powerful evil, but Fellowship builds its world and its characters with such care that every scene adds to your understanding of both. Battlefield Earth has no functioning scene — the world has no internal logic, the characters have no personalities, and the evil makes no coherent choices.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130128, 31274, 1, 'ofirgelbart74', 'Both are long films about power structures and those who challenge them, but The Godfather earns every one of its three hours with scenes that are studied in film schools decades later. Battlefield Earth earned a Razzie for Worst Picture of the Decade. The recommendation exists only as a contrast that makes the original''s achievement more visible.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130953, 86263, 2, 'ofirgelbart74', 'Die Another Day is the Bond film that broke the formula — the invisible Aston Martin and the CGI surfboard sequence have not aged at all, and the film feels like it was made by people who loved the idea of Bond films but had no instinct for what made them work. Goldfinger''s confidence and practical stunt work have no equivalent in Die Another Day.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (312170, 86263, 2, 'ofirgelbart74', 'The Spy Who Loved Me committed to practical spectacle — the Lotus submarine, the ski parachute opening — in ways that still impress. Die Another Day committed to CGI spectacle that looks worse every year. The same franchise formula at its most confident versus its most overextended.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (120574, 86263, 2, 'ofirgelbart74', 'From Russia with Love works because the threat is always physical and plausible — Red Grant is a human being who can actually beat Bond in a fight, and the Orient Express compartment makes that fight feel genuinely dangerous. Die Another Day''s threats are mostly CGI and the invisible car eliminates the physical logic that makes spy films tense.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (215876, 310728, 2, 'ofirgelbart74', 'Speed worked because the constraint was brilliant — a bus that can''t slow down creates perfect action-film geometry. Speed 2 puts the same premise on a cruise ship, which removes every tension that made the original work. A cruise ship that can''t stop is not scary because cruise ships are already slow. Mission Impossible fans will find Speed 2 structurally incoherent.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (256632, 310728, 2, 'ofirgelbart74', 'Both are nautical action films but Speed 2''s cruise ship setting eliminates every kind of urgency that made Speed work — and unlike Pirates of the Caribbean, which has Jack Sparrow to carry every scene, Speed 2 replaced Keanu Reeves with Jason Patric and lost all its charisma in one casting decision.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (328277, 310728, 2, 'ofirgelbart74', 'Both feature Sandra Bullock in a major action role — T2 as an incidental character whose scenes work perfectly, Speed 2 as the lead of a film that doesn''t know what it wants to be. T2''s action sequences work because Cameron made every choice in service of physical logic; Speed 2''s cruise-ship finale is spectacular in the emptiest possible way.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (333856, 310728, 2, 'ofirgelbart74', 'Both are 1997 large-scale films involving ships in crisis, but Titanic made you care about Jack and Rose over three hours before the ship sinks so the disaster feels personal. Speed 2 introduces characters and disasters simultaneously and never makes you care about either. The same year, the same setting, entirely different emotional experiences.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194497, 194493, 2, 'ofirgelbart74', 'The 1978 animated Lord of the Rings uses rotoscoping — tracing live-action footage frame by frame — which creates an uncanny, uncomfortable visual quality that works against the fantasy rather than building it. Jackson''s Fellowship spent two years in New Zealand creating a world you believe in completely; Bakshi''s version is an interesting historical artifact that never achieved what it attempted.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (294028, 174918, 2, 'ofirgelbart74', 'Both feature a magical being granting wishes to a child in a contemporary setting, but Kazaam is built entirely around Shaquille O''Neal''s celebrity rather than any cinematic ideas — the rapping genie sequences exist to showcase a persona, not to tell a story. Fans of Spirited Away''s careful visual storytelling will find Kazaam''s personality-first approach completely hollow.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (96593, 174918, 2, 'ofirgelbart74', 'Both are films about a child forming a bond with a magical being who doesn''t belong in the normal world — but E.T. earns its emotion because Spielberg treats the friendship as completely real and the goodbye as genuinely heartbreaking. Kazaam treats its central relationship as a vehicle for Shaq''s comedy and musical performance, and the bond never feels like anything.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (159175, 174918, 1, 'ofirgelbart74', 'Both feature a child protagonist in a magical adventure involving an unusual companion, but Temple of Doom commits fully to its dark adventure tone while Kazaam commits fully to Shaquille O''Neal''s basketball celebrity. The mine cart chase and the Kazaam rap sequence are in entirely different categories of filmmaking.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (337166, 174918, 2, 'ofirgelbart74', 'Both are family films about a child''s relationship with a magical figure who has to learn something about friendship — but Toy Story''s Woody and Buzz are fully written characters with genuine psychological needs, while Kazaam''s genie is a celebrity showcase with a wish-granting mechanic. The emotional precision Pixar built is simply not present anywhere in Kazaam.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 310992, 1, 'ofirgelbart74', 'Both are late-90s ensemble films with a large following, but Spice World is a feature-length music video with no plot — scenes begin and end with no connection to each other, and the film''s only purpose is to promote the Spice Girls'' tour and album. Fans of The Matrix who enjoy films that ask genuine philosophical questions will find Spice World bewildering.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (313459, 310992, 1, 'ofirgelbart74', 'Both are films about an ensemble of characters with distinct personalities going on an adventure together — but Star Wars builds genuine relationships between its characters and puts them in real danger, while Spice World puts its characters in a bus and has them perform their personalities for the camera. Not a comparable cinematic experience in any respect.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (109093, 31274, 1, 'ofirgelbart74', 'Both involve a protagonist outmatched by more powerful and better-organized adversaries, but Fargo''s criminals are incompetent and human and recognizable, while Battlefield Earth''s aliens are incompetent in ways the screenplay doesn''t seem to notice. Marge Gunderson is one of cinema''s great characters; Battlefield Earth has no comparable creation.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (290070, 129439, 1, 'ofirgelbart74', 'Both are biographical narratives about a person rising against adversity — Schindler''s transformation from opportunist to moral hero is one of cinema''s great character arcs. Glitter is a music-industry rise-to-fame story built around a pop star persona that never becomes a film performance. The comparison exists only to illuminate the gap between one and the other.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (210511, 30965, 2, 'ofirgelbart74', 'Both feature protagonists who struggle to understand what is real in a chaotic situation — Leonard through amnesia, Bruce through trauma. But Batman Forever''s competing villains drain any chance for that psychological theme to breathe, while Memento''s entire structure is built around putting the audience inside the experience of cognitive uncertainty.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (65764, 151052, 1, 'ofirgelbart74', 'Both use graphic violence as a central formal element, but Kubrick''s violence in A Clockwork Orange is always deliberate — the camera placement, the music choice, the editing rhythm all force you to think about what you are watching. House of the Dead''s violence is just loud and frequent with no equivalent intention behind it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (291698, 151052, 1, 'ofirgelbart74', 'Both are genre films in which death and violence are the primary spectacle, but Se7en''s horror comes from John Doe''s intelligence and planning — the crimes are designed to mean something. House of the Dead''s horror comes from zombies running at the camera. Fans of Fincher''s controlled, psychological approach to violence will find Boll''s approach completely alien.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (82967, 127627, 1, 'ofirgelbart74', 'Both are crime films with A-list casts in scenes together, but The Departed''s ensemble builds real tension from the first scene and sustains it to the final minute. Gigli''s ensemble generates no tension at any point — the film has no functioning scenes, and the criminal threat it sets up never pays off in any satisfying way.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (297838, 31274, 1, 'ofirgelbart74', 'Both are films about people trapped inside an oppressive system who eventually escape it — Shawshank builds Andy''s escape over twenty years of patient, brilliant detail. Battlefield Earth''s humans escape their alien oppressors by finding some nuclear bombs and the film expects you to feel satisfied. Everything Darabont built with care, Battlefield Earth dismantles with indifference.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (319613, 30952, 2, 'ofirgelbart74', 'Both are superhero sequels with multiple villains and a heightened camp register, but Superman II''s ''Kneel before Zod'' works because Terence Stamp plays Zod with complete conviction — the campiness has menace behind it. Batman & Robin''s campiness has nothing behind it: no menace, no stakes, no reason for any scene to exist.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130129, 127627, 1, 'ofirgelbart74', 'Both are crime films featuring professional criminals in situations where trust is the central issue — but Godfather II''s Michael and Fredo have one of cinema''s most devastating betrayal scenes, while Gigli''s criminals have conversations that communicate nothing about their relationship or their situation. The films are in entirely different categories of craftsmanship.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (96593, 73574, 2, 'ofirgelbart74', 'Both are films about extraterrestrials visiting Earth in a suburban setting — but E.T. is about a child''s friendship with a benevolent alien who wants to go home, and Critters 3 is about small furry aliens eating people in an apartment building. The emotional register is completely opposite, and Critters 3 is notable mainly as Leonardo DiCaprio''s debut role.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (328277, 219541, 1, 'ofirgelbart74', 'Both feature action sequences where the hero fights an apparently unstoppable enemy — but T2''s T-1000 was designed by Stan Winston''s practical effects team to feel physically real, and every encounter with it generates genuine threat. Mortal Kombat Annihilation''s CGI villains never feel physically present and the encounters with them generate nothing.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (165961, 370017, 2, 'ofirgelbart74', 'Both are films about a protagonist who must stop a threat through improvisation — but Jaws builds its dread slowly over two hours and makes you feel every minute of the shark''s invisible presence. XXX shows its threats immediately and at full volume from the first scene. Spielberg withheld the shark to make its arrival terrifying; XXX has no equivalent restraint.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (46169, 365498, 2, 'ofirgelbart74', 'Both are period action films about a hero defying a more powerful antagonist, but Braveheart''s William Wallace is a man whose every action is motivated by genuine love and loss. Wild Wild West''s James West is motivated mainly by being Will Smith and having a large CGI spider to fight. The emotional investment Braveheart built has no equivalent in Wild Wild West.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (267038, 310992, 1, 'ofirgelbart74', 'Both are ensemble films structured as loosely connected vignettes, but Tarantino''s vignettes all build toward a complete moral argument about violence and choice. Spice World''s vignettes exist to showcase each Spice Girl''s personality for fans who already know them — there is no equivalent structural intention behind the film''s format.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (109093, 127627, 1, 'ofirgelbart74', 'Both are crime films where two mismatched people have to work together on a criminal task — but Fargo''s mismatched criminals are precisely observed and darkly funny, and Marge''s investigation of their incompetence is one of cinema''s great comic performances. Gigli''s mismatched pair have no chemistry and no comedic timing, and the film never figures out what kind of movie it wants to be.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (112290, 109093, 9, 'ofirgelbart74', 'Both films build a world that feels hyper-real and slightly off, where the protagonist is the least reliable person in the room. Fight Club''s unnamed narrator and Fargo''s Jerry Lundegaard are both men whose plans spiral completely out of their control, and both films use dark humor to make you laugh at situations that should horrify you.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 207992, 9, 'ofirgelbart74', 'Both films introduce a protagonist who discovers the world is far more dangerous and mythological than he realized, and both deliver action sequences that genuinely changed what audiences expected from the genre. Raiders invented the modern adventure template; The Matrix invented the modern action template. Watching them back to back shows how each redefined its era.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 328285, 9, 'ofirgelbart74', 'Both films center on a machine intelligence hunting a human target while a protector tries to stop it, and both were technically groundbreaking in ways that permanently changed visual effects. T2''s liquid metal morphing and The Matrix''s bullet time each made audiences gasp in theaters and immediately dated every action film that came before them.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (129185, 271095, 8, 'ofirgelbart74', 'Both are crowd-pleasing adventure films built around a charismatic hero navigating a world of ancient power and dangerous enemies. Gladiator''s arena sequences and Raiders'' action set pieces share the same DNA — practical stunts, physical danger that feels real, and a hero who wins through intelligence as much as strength.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (167260, 194500, 10, 'ofirgelbart74', 'The Two Towers builds directly on everything Fellowship established — the friendships, the geography, the stakes — and delivers the Helm''s Deep battle that Fellowship was building toward from the beginning. Watching them together is the only way to experience the full emotional arc of Frodo and Sam''s friendship, which is the actual heart of the entire trilogy.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194500, 32114, 8, 'ofirgelbart74', 'Both are films where a protagonist is chosen for a mission he did not seek and must carry a burden that slowly isolates him from everyone around him. Frodo''s ring and Nash''s genius both transform from gifts into sources of suffering, and both films are ultimately about the people who stay beside the protagonist when the burden becomes unbearable.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271192, 32114, 9, 'ofirgelbart74', 'Both films center on a man with an exceptional mind that works differently from everyone around him, and both use a relationship — Rain Man with his brother, A Beautiful Mind with his wife — as the anchor that keeps the protagonist connected to the world. Dustin Hoffman and Russell Crowe both give performances that make you forget you are watching an actor.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 271192, 9, 'ofirgelbart74', 'Both films follow a protagonist with cognitive differences who navigates a world built for people unlike him, and both use that protagonist''s outsider perspective to reveal something true about American society. Forrest and Raymond are both at their best when the people around them finally stop treating them as problems to manage and start treating them as people worth knowing.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (26844, 328285, 8, 'ofirgelbart74', 'Both films are time-travel stories where the entire plot depends on preventing a specific future, and both use time mechanics that are internally consistent enough to make the stakes feel real. Back to the Future''s clock tower sequence and T2''s final act both work as pure suspense regardless of how much you know about time travel theory.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (207992, 26844, 8, 'ofirgelbart74', 'Both films introduce a protagonist who is told that everything he believed about reality is wrong, and both have a mentor figure who delivers that revelation in a way that is somehow both overwhelming and exciting. Doc Brown and Morpheus are very different people but they perform the same structural function — they are the reason the protagonist chooses to go on the adventure.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130128, 297838, 8, 'ofirgelbart74', 'Both are films that take their time — long, deliberate, and completely confident that you will stay with them — and both reward that patience with endings that feel genuinely earned. The Godfather and Shawshank Redemption are both films where performance is everything, and both have supporting characters (Clemenza, Red) who are as memorable as the leads.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280270, 117874, 8, 'ofirgelbart74', 'Both are films about a man from modest origins who becomes extraordinary not through brilliance but through perseverance and an inability to give up. Rocky''s training montage and Forrest''s running across America both tap into the same feeling — that the effort itself is the point, regardless of where it leads.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (290070, 130128, 9, 'ofirgelbart74', 'Both films follow a powerful man who operates in a morally corrupt system and must decide how much of himself to sacrifice to that system. Schindler''s transformation from profiteer to rescuer and Michael Corleone''s transformation from innocent to patriarch are mirror images — one man finds his humanity while the other loses it, and both journeys are unforgettable.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194500, 129185, 8, 'ofirgelbart74', 'Both films were released within a year of each other and both reminded audiences that epic filmmaking built around physical production and genuine emotional stakes was still possible. Fellowship''s New Zealand landscapes and Gladiator''s Rome share a commitment to making fantasy worlds feel inhabited and real rather than digitally assembled.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271095, 280270, 8, 'ofirgelbart74', 'Both are films built entirely around the physical performance of their lead actor, where the joy of watching comes from seeing a human body pushed to its limits. Harrison Ford taking actual punches and Sylvester Stallone running up actual stairs share the same quality — you believe in them because you can see the effort is real.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (297838, 370017, 2, 'ofirgelbart74', 'Both follow a protagonist who refuses to accept his situation and fights the system constraining him — but Shawshank builds that resistance over nineteen years of patience and quiet dignity, while XXX builds it over one scene of Vin Diesel doing a skateboard trick. The emotional weight of Andy''s tunnel has no equivalent anywhere in XXX.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130128, 30952, 1, 'ofirgelbart74', 'Both films feature powerful men operating outside the law in a city that cannot control them — but The Godfather treats that premise with the weight it deserves, while Batman and Robin treats it as an excuse for bat nipples and ice puns. They share a genre ancestor but are otherwise from completely different cinematic universes.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 174918, 1, 'ofirgelbart74', 'Both films feature a protagonist who forms an unlikely friendship that changes his life, and both use that friendship to deliver a message about hope. Forrest Gump uses its friendship to say something true about human connection. Kazaam uses its friendship to sell Shaquille O''Neal as a wish-granting genie. The sincerity gap between them is unbridgeable.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (290070, 313474, 1, 'ofirgelbart74', 'Both films are about a pivotal moment in a larger conflict where the fate of many depends on one person''s choices — but Schindler''s List earns every moment of its emotional weight through restraint and specificity, while Episode I spends its pivotal moment on midi-chlorian explanations and Jar Jar Binks. They are both long films but only one earns its length.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 30952, 1, 'ofirgelbart74', 'Both films were produced by major Hollywood studios with enormous resources and both tell stories about extraordinary individuals in extraordinary circumstances. Forrest Gump uses those resources to create something genuinely moving. Batman and Robin uses those resources to create something that drove its lead actor to publicly apologize to reporters.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271192, 310992, 1, 'ofirgelbart74', 'Both films follow a group of people traveling together whose different personalities create friction and comedy on the road. Rain Man''s road trip between Charlie and Raymond becomes a genuine exploration of what the two brothers mean to each other. Spice World''s road trip exists to film the Spice Girls doing photoshoots and arguing about nothing with no emotional consequence.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280270, 311492, 2, 'ofirgelbart74', 'Rocky V brings back the street-fighting origins of the first film and tries to recapture its underdog spirit — but it replaces Adrian''s supportive presence with a plot about Rocky losing his fortune and his son''s attention to a new protégé. The emotional logic that made the original work is present here but diluted by a story that feels constructed rather than felt.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (26844, 26847, 3, 'ofirgelbart74', 'Part III takes the same characters and the same time-travel mechanics to the Old West, and it is a competent and occasionally charming film — but it lacks the clockwork plot precision of the original. The first film''s clock tower sequence has a structural elegance that Part III''s train finale tries to replicate but cannot quite achieve.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (194500, 207991, 2, 'ofirgelbart74', 'Both films are the beginning and end of epic trilogies built around a messianic protagonist fighting to save humanity. Fellowship uses its three hours to introduce a world you genuinely believe in. Revolutions uses its two hours to conclude a trilogy whose philosophical ambitions had by the third film completely outpaced its ability to dramatize them.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130128, 127627, 1, 'ofirgelbart74', 'Both films are about criminals forced into an uncomfortable partnership who gradually develop a relationship neither expected. The Godfather''s criminal partnerships are built on loyalty, fear, and genuine power dynamics. Gigli''s criminal partnership is built on Ben Affleck and Jennifer Lopez''s real-life relationship, which the camera seems more interested in than the plot.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (26844, 174918, 1, 'ofirgelbart74', 'Both films are family-friendly adventures built around a fantastical premise that requires the audience to simply accept the rules and enjoy the ride. Back to the Future makes that acceptance easy because its internal logic is so tight. Kazaam makes that acceptance difficult because its internal logic consists entirely of whatever was required to put Shaquille O''Neal on screen that week.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (280270, 30952, 1, 'ofirgelbart74', 'Both films are about underdogs who train obsessively to face a more powerful opponent in a climactic battle. Rocky''s training sequences are among cinema''s most purely motivating moments. Batman and Robin''s training sequences involve ice skates, a zamboni, and Mr. Freeze asking his henchmen to "chill." They share a structure but absolutely nothing else.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (297838, 280270, 9, 'ofirgelbart74', 'Both films are about men who refuse to let their circumstances define them, and both end with moments of triumph that feel completely earned after everything the protagonist has endured. Andy Dufresne crawling through a sewer to reach freedom and Rocky Balboa going the distance with Apollo Creed are two of cinema''s most purely satisfying endings.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (130128, 326155, 9, 'ofirgelbart74', 'Both are films about men destroyed by the world they chose to inhabit — Michael Corleone becomes the monster he swore he would never be, Travis Bickle cannot escape the city that is slowly consuming him. Coppola and Scorsese were making the same film from different angles, and watching both back to back is the most complete portrait of American masculinity cinema ever produced.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 297838, 9, 'ofirgelbart74', 'Both are 1994 films that earn their endings in ways I didn''t expect going in. One is about a man who runs across America and the other about a man who tunnels out of prison — both refuse to let their protagonist be defined by what the world decided about him. The year these two came out made the 90s feel like something special.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (32114, 297838, 8, 'ofirgelbart74', 'Both films are about intelligent men who find ways to survive systems designed to break them. Nash builds mathematics in his head and Dufresne builds a tunnel in secret, and watching both you believe completely in the quiet determination of both men.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271192, 117874, 9, 'ofirgelbart74', 'The road trip in Rain Man and the running in Forrest Gump are the same story told from different angles — both are about a man the world underestimated who teaches the people around him more than he realizes. Hoffman and Hanks both disappear completely into their roles.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (26844, 271095, 9, 'ofirgelbart74', 'Both films defined what adventure meant in the 1980s — a hero with a ticking clock and a set piece at the end you are still thinking about on the way home. Watching both back to back you realize how rare it is to make a film this fun that also feels completely earned.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (290070, 297838, 8, 'ofirgelbart74', 'Both are films I did not want to watch because I knew they would be heavy and both destroyed me in the best way. One is about a man who saves people inside a system designed to murder them, the other about a man who saves himself inside a system designed to break him.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (56871, 238072, 9, 'ofirgelbart74', 'Both films treat crime as a pleasure rather than a problem — DiCaprio''s Abagnale runs around the world charming everyone he meets and Clooney''s Danny Ocean assembles the smartest team in the room. I rewatched both in the same week and both times forgot I was supposed to be rooting against the criminal.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (25192, 56304, 8, 'ofirgelbart74', 'DiCaprio''s Howard Hughes and De Niro''s Sam Rothstein are the same man in different decades — both built empires through obsessive precision and both couldn''t stop when they should have. The Aviator made me feel the specific loneliness of a man who controls everything except himself.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271192, 297838, 8, 'ofirgelbart74', 'Both films take someone the world wrote off and let you spend two hours watching them refuse to accept that verdict. Raymond does it through routine and Andy does it through patience — different methods, the same refusal to be reduced to what other people decided about them.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (26844, 26846, 8, 'ofirgelbart74', 'Part II is the only sequel I can think of that makes the original more fun rather than diminishing it — the third act revisits 1955 from a different angle and made me want to pause and rewatch the first film immediately. The clockwork plotting that made the original so satisfying doubles here.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (32114, 30952, 1, 'ofirgelbart74', 'A Beautiful Mind is about a man whose brilliant mind shows him things that aren''t real. Batman and Robin shows you things that are real — ice puns, rubber nipples, a Batmobile that makes no sense — and you wish they weren''t there. The comparison does not flatter Batman and Robin.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271192, 30952, 1, 'ofirgelbart74', 'Rain Man works because Hoffman plays Raymond''s internal world with complete precision and you feel the film was made by people who cared about getting that right. Batman and Robin was made by people who cared about the toy line. Both feature unusual characters — only one treats that with any respect.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (117874, 365498, 2, 'ofirgelbart74', 'Both are films about an American hero moving through history with charm and spectacle. Forrest Gump uses that premise to make you feel thirty years of American life through one pair of eyes. Wild Wild West uses it to put Will Smith on a giant mechanical spider and call it a movie.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (26844, 31274, 1, 'ofirgelbart74', 'Back to the Future works because every complication follows logically from the time mechanics and the script earns every laugh. Battlefield Earth follows no logic I could identify, and the Dutch-angle cinematography made me feel like it was shot by someone who had never seen a film before.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (32114, 127627, 1, 'ofirgelbart74', 'Both films are about intelligent people in complicated situations where nothing goes as planned. A Beautiful Mind makes that feel psychologically real and earns its ending. Gigli''s complicated situation involves a kidnapping and generates not one moment that functions as intended.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (25192, 30952, 1, 'ofirgelbart74', 'The Aviator is about a man who would not compromise his vision and built something extraordinary. Batman and Robin is about a director who compromised every aspect of a beloved character and built something that drove its own star to publicly apologize for being in it.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (56871, 31274, 1, 'ofirgelbart74', 'Abagnale''s cons work in Catch Me If You Can because Spielberg makes each one feel plausible. Battlefield Earth''s solution to alien occupation involves teaching primitive humans to fly Harrier jets in one week. The film expects you to find this convincing and I was not able to do that.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (271192, 365498, 2, 'ofirgelbart74', 'Both follow two men who shouldn''t work together and slowly discover they do. Rain Man earns that through genuine character development over two hours. Wild Wild West has its pair argue for ninety minutes and then a giant mechanical spider appears and the film considers its job done.', NULL);
INSERT INTO movies_recommendations (`base_movie_id`,`recommended_movie_id`,`recommendation`,`suggested_by`,`justification`,`comment`) VALUES (32114, 310992, 1, 'ofirgelbart74', 'A Beautiful Mind is about a community rallying around someone who is struggling — every scene between Nash and his colleagues feels earned and real. Spice World is about five people on a bus doing photoshoots. Not the same category of filmmaking and not a fair comparison to make.', NULL);
